// Parse Recruiter Output - Tie-breaker only (no bonus to fit_score)
try {
  let raw = $json.output || $json;

  // Nếu AI trả về {output:"[...json...]"} thì lấy phần bên trong
  if (typeof raw === 'object' && raw.output) raw = raw.output;

  // Làm sạch chuỗi JSON nếu cần
  if (typeof raw === 'string') {
    const match = raw.match(/\[\s*{[\s\S]*}\s*\]/);
    if (match) raw = match[0];
    raw = raw.trim().replace(/^[\uFEFF\x00-\x1F]+/, '');
  }

  // Thử parse JSON (kể cả khi bị double-encode)
  let parsed;
  try {
    parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch (innerErr) {
    parsed = JSON.parse(JSON.parse(raw));
  }

  // Chuẩn hóa thành mảng
  const arr = Array.isArray(parsed) ? parsed : [parsed];
  if (!arr.length) throw new Error("Không có dữ liệu ứng viên hợp lệ");

  // Helpers
  const norm = (s) => (s || '').toLowerCase().trim();
  const domEq = (cv) => norm(cv.cv_domain) && norm(cv.jd_domain) && norm(cv.cv_domain) === norm(cv.jd_domain);
  const domNear = (cv) => {
    const a = norm(cv.cv_domain), b = norm(cv.jd_domain);
    if (!a || !b) return false;
    return a.includes(b) || b.includes(a);
  };
  const kwLen = (cv) => Array.isArray(cv.matched_keywords) ? cv.matched_keywords.length : 0;
  const years = (cv) => Number(cv.cv_years || 0);

  // Đồng bộ nhãn hiển thị và auto-fix domain_match nếu AI sai
  const candidates = arr.map(cv => {
    const c = { ...cv };
    // Role match label = đúng domain CV (không “Other” cứng)
    c.role_match_label = (c.cv_domain || '').trim() || 'Không xác định';

    // Auto-fix: nếu domain bằng nhau mà domain_match = false thì sửa thành true
    if (domEq(c) && c.domain_match === false) c.domain_match = true;

    return c;
  });

  // Tổng và danh sách đạt chuẩn
  const total = candidates.length;
  const qualified = candidates.filter(cv => (cv.fit_score || 0) >= 70);

  // Comparator chọn ứng viên tốt nhất:
  // 1) fit_score cao hơn thắng
  // 2) Nếu bằng nhau: domain = JD thắng
  // 3) Nếu vẫn bằng nhau: domain gần JD thắng
  // 4) Nếu vẫn bằng nhau: nhiều matched_keywords hơn thắng
  // 5) Nếu vẫn bằng nhau: cv_years nhiều hơn thắng
  const better = (a, b) => {
    const fa = Number(a.fit_score || 0);
    const fb = Number(b.fit_score || 0);
    if (fa !== fb) return fa > fb ? a : b;

    const aEq = domEq(a), bEq = domEq(b);
    if (aEq !== bEq) return aEq ? a : b;

    const aNear = domNear(a), bNear = domNear(b);
    if (aNear !== bNear) return aNear ? a : b;

    const aKw = kwLen(a), bKw = kwLen(b);
    if (aKw !== bKw) return aKw > bKw ? a : b;

    const aY = years(a), bY = years(b);
    if (aY !== bY) return aY > bY ? a : b;

    return a; // giữ nguyên thứ tự nếu vẫn hòa
  };

  const best = candidates.reduce((acc, cv) => acc ? better(acc, cv) : cv, null);

  // Summary luôn dùng fit_score “gốc” (không cộng thưởng)
  const summary_text =
    best && (best.fit_score || 0) >= 70
      ? `🏆 Ứng viên điểm đánh giá cao nhất: ${best.candidate_name || "(Không xác định)"} (${best.fit_score}%)`
      : `Không có hồ sơ phù hợp. Đề xuất tìm thêm ứng viên khác.`;

  return [{
    json: {
      total_candidates: total,
      qualified_candidates: qualified.length,
      best_candidate: best?.candidate_name || "",
      best_score: best?.fit_score || 0,
      summary_text,
      candidates
    }
  }];

} catch (err) {
  return [{
    json: {
      error: "JSON_PARSE_FAILED",
      message: err.message,
      raw_snippet: String($json.output || '').slice(0, 500)
    }
  }];
}

const body = $json.body || {};
const jd = body.message || "JD chưa xác định";
const files = Array.isArray(body.files) ? body.files : [];

return files.map((f, i) => ({
  json: {
    jd,
    index: i + 1,
    filename: f.name || `file_${i + 1}.pdf`,
    base64: (f.data || "").split(",")[1] || "",
  }
}));

// Detect PDF type: text-based or scanned image

// Lấy thông tin cơ bản
const jd = $json.jd || "JD chưa xác định";
const index = $json.index || 1;
const filename = $json.filename || `cv_${index}.pdf`;
const base64 = $json.base64 || "";

// Nếu không có base64 thì bỏ qua
if (!base64) {
  return {
    json: {
      jd,
      index,
      filename,
      base64: null,
      pdf_type: "unknown",
      note: "⚠️ Không có dữ liệu base64 để kiểm tra."
    }
  };
}

try {
  // Chuyển base64 → text để dò nội dung readable
  const pdfBuffer = Buffer.from(base64, "base64");
  const text = pdfBuffer.toString("utf8");

  // Regex kiểm tra xem có đoạn text đọc được hay không
  const hasReadableText = /[A-Za-zÀ-ỹ0-9]{3,}/.test(text);
  const pdf_type = hasReadableText ? "text" : "scan";

  return {
    json: {
      jd,
      index,
      filename,
      base64, // 👈 Giữ lại base64 để node sau còn dùng
      pdf_type,
      note: hasReadableText
        ? "✅ PDF có lớp text, đọc được."
        : "⚠️ PDF dạng ảnh, không có lớp text."
    }
  };

} catch (err) {
  return {
    json: {
      jd,
      index,
      filename,
      base64, // vẫn giữ để debug khi lỗi
      pdf_type: "error",
      note: "❌ Lỗi khi đọc base64: " + err.message
    }
  };
}

// Convert base64 → Binary cho từng CV

const base64 = $json.base64 || "";
const jd = $json.jd || "JD chưa xác định";
const index = $json.index || 1;
const filename = $json.filename || `cv_${index}.pdf`;

// Nếu không có dữ liệu base64 thì bỏ qua
if (!base64) {
  return {
    json: {
      jd,
      index,
      filename,
      note: "⚠️ Không có dữ liệu base64 để convert."
    }
  };
}

return {
  json: {
    jd,
    index,
    filename
  },
  binary: {
    data: {
      data: Buffer.from(base64, "base64"),
      mimeType: "application/pdf",
      fileName: filename
    }
  }
};

// Node: Reattach_Metadata_After_Extract (bản nâng cấp full logic)
// Tác dụng: Gắn lại jd, filename, text, và tự đọc candidate_name, candidate_position, role_match_type

const extracted = $input.all(); // Kết quả từ Extract From File
const srcItems = $items("Convert Base64 to Binary", 0); // Dữ liệu gốc có jd, filename, index

// ====== HÀM TIỆN ÍCH ======
const normalize = (s) => (s || "").replace(/\s+/g, " ").trim();

const cleanName = (name) => {
  return name
    .replace(/[^\p{L}\s]/gu, "")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b(\p{L})/gu, (m) => m.toUpperCase());
};

return extracted.map((ex, i) => {
  const src = (srcItems[i] && srcItems[i].json) ? srcItems[i].json : {};
  const text = ex.json?.text || "";
  const lines = text.split(/\n/).map(l => l.trim()).filter(Boolean);
  const header = lines.slice(0, 5).join(" ");

  let candidateName = "";
  let candidatePosition = "";
  let roleMatchType = "Other";

  // ====== 1️⃣ XÁC ĐỊNH TÊN ỨNG VIÊN ======
  // Dạng đầy đủ: "Nguyen Thi Ngoc Phuong"
  const fullNameRegex = /\b([A-ZĐ][a-zàáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđĐ]{1,}\s){1,4}[A-ZĐ][a-zàáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđĐ]{2,}/gu;
  const matchName = header.match(fullNameRegex);
  if (matchName) candidateName = cleanName(matchName[0]);

  // Dạng viết tắt: N.T.K.Diễm, L.T.M.Trinh
  if (!candidateName) {
    const abbr = header.match(/[A-Z]\.[A-Z]\.[A-Z]\.[A-Za-zÀ-ỹ]{2,}/);
    if (abbr) candidateName = abbr[0].replace(/\./g, " ").trim();
  }

  // Tên nằm trong “Thông Tin Cá Nhân” hoặc “Họ và Tên”
  if (!candidateName) {
    const infoBlock = text.match(/(Họ\s*và\s*tên|Thông\s*Tin\s*Cá\s*Nhân)[\s\S]{0,150}/i);
    if (infoBlock) {
      const found = infoBlock[0].match(fullNameRegex);
      if (found) candidateName = cleanName(found[0]);
    }
  }

  // ====== 2️⃣ XÁC ĐỊNH CHỨC DANH (VỊ TRÍ) ======
  const roleRegex = /(Team\s*Leader|Manager|Consultant|Specialist|Developer|Engineer|Officer|Supervisor|Coordinator|Executive|Director|Leader|Nhân\s*viên\s*[^\n,;]+|Chuyên\s*viên\s*[^\n,;]+|Trưởng\s*[^\n,;]+|Giám\s*sát\s*[^\n,;]+)/i;
  const matchRole = text.match(roleRegex);
  if (matchRole) candidatePosition = normalize(matchRole[0]);

  // ====== 3️⃣ PHÂN LOẠI role_match_type ======
  if (/Manager|Director|Trưởng/i.test(candidatePosition)) roleMatchType = "Manager";
  else if (/Consultant|Functional|Analyst|Specialist|Officer/i.test(candidatePosition)) roleMatchType = "Functional";
  else if (/Developer|Technical|Engineer|Programmer|Basis/i.test(candidatePosition)) roleMatchType = "Technical";
  else if (/Admin|Hành\s*chánh|Nhân\s*sự/i.test(candidatePosition)) roleMatchType = "Admin";
  else roleMatchType = "Other";

  // ====== 4️⃣ KẾT QUẢ ======
  return {
    json: {
      jd: src.jd ?? null,
      index: src.index ?? (i + 1),
      filename: src.filename ?? ex?.binary?.data?.fileName ?? null,
      text,
      info: ex.json?.info ?? {},
      candidate_name: candidateName || null,
      candidate_position: candidatePosition || null,
      role_match_type: roleMatchType
    }
  };
});

// --- Combine_Candidates_For_AI ---
// Gom tất cả các CV thành mảng candidates[] để AI Agent đọc
// Đồng thời tự động lấy dòng tên đầu tiên trong CV (ví dụ: "N.T.K.Diễm", "L.T.M.Trinh")

function extractRawName(text = "") {
  if (!text) return "";

  const lines = text
    .replace(/\r/g, "")
    .replace(/\t/g, " ")
    .split("\n")
    .map(l => l.trim())
    .filter(l => l && l.length > 1)
    .slice(0, 8); // chỉ xem vài dòng đầu tiên

  // Bỏ qua các dòng chứa cụm từ “Thông tin cá nhân”, “CV”, “Sơ yếu lý lịch”, “Curriculum Vitae”
  const skip = /(thông tin|sơ yếu|curriculum vitae|cv|profile)/i;
  const filtered = lines.filter(l => !skip.test(l));

  // Lấy dòng đầu tiên hợp lệ (giữ nguyên format, không sửa gì)
  return filtered.length ? filtered[0] : "";
}

return [
  {
    json: {
      jd: $items("Reattach_Metadata_After_Extract")[0].json.jd,
      candidates: $items("Reattach_Metadata_After_Extract").map(item => {
        const text = item.json.text || "";
        const nameFromText = extractRawName(text);

        return {
          filename: item.json.filename,
          // Ưu tiên tên trích từ text, nếu rỗng mới lấy tên cũ
          candidate_name: nameFromText || item.json.candidate_name || "",
          candidate_position: item.json.candidate_position || "",
          role_match_type: item.json.role_match_type || "Other",
          text
        };
      })
    }
  }
];

// --- Node: Preprocess_CV_Names ---
// Mục tiêu: lấy đúng dòng đầu tiên (tên thô trong CV), bỏ qua các dòng như "Thông tin cá nhân", "CV", "Sơ yếu lý lịch".
// Không đổi hoa/thường, không bỏ dấu, không bỏ dấu chấm.

function extractRawName(text = "") {
  if (!text) return "";

  const lines = text
    .replace(/\r/g, "")
    .replace(/\t/g, " ")
    .split("\n")
    .map(l => l.trim())
    .filter(l => l && l.length > 1)
    .slice(0, 8); // chỉ quét vài dòng đầu CV

  // Bỏ qua dòng chứa "Thông tin cá nhân", "CV", "Curriculum Vitae"...
  const skip = /(thông tin|sơ yếu|curriculum vitae|cv|profile)/i;
  const filtered = lines.filter(l => !skip.test(l));

  // Lấy dòng đầu tiên còn lại (giữ nguyên xi)
  return filtered.length ? filtered[0] : "";
}

return $input.all().map(item => {
  const t = item.json.text || "";
  const name = extractRawName(t);

  // Debug xem đọc ra gì
  console.log("📄 File:", item.json.filename, "→ Name:", name);

  return {
    json: {
      ...item.json,
      // Ép cập nhật lại tên, KHÔNG fallback
      candidate_name: name,
    },
  };
});
